/** @format */

import React from "react";
import "./about.css";
import AboutImg from "../../assets/about.jpg";

import CV from "../../assets/Anusha-Cv.pdf";
import Info from "./Info";

const About = () => {
	return (
		<section className="about section" id="about">
			<h2 className="section__title">About Me</h2>
			<span className="section__subtitle">My introduction</span>

			<div className="about__container container grid">
				<img src={AboutImg} alt="" className="about__img" />

				<div className="about__data">
					<Info />

					<p className="about__description">
						Experienced Data Analyst with a focus on consulting projects at
						FedEx Ground. Skilled in analyzing large datasets, generating
						actionable insights, and effectively communicating findings to
						stakeholders. Seeking opportunities in software engineering to
						leverage my analytical expertise and contribute to organizational
						success.
					</p>

					<a download="" href={CV} className="button button--flex">
						Download CV
					</a>
				</div>
			</div>
		</section>
	);
};

export default About;
